import {
  createField,
  setFieldError,
  setFieldValue,
  newLineId,
} from '../../../../form-shared';
import type { IField } from '../../../../form-shared';
import {
  CASH_VOUCHER_DISPLAY_ONLY_HEADER_KEYS,
  type CashVoucherHeaderKey,
  type CashVoucherHeaderModel,
} from '../types/cashVoucherHeader.types';
import type { CashVoucherLineModel } from '../types/cashVoucherLine.types';

export { createField, setFieldValue, setFieldError, newLineId };

export function initHeaderFields(model: CashVoucherHeaderModel): Record<CashVoucherHeaderKey, IField<string>> {
  const out = {} as Record<CashVoucherHeaderKey, IField<string>>;
  (Object.keys(model) as CashVoucherHeaderKey[]).forEach(key => {
    const displayOnly = CASH_VOUCHER_DISPLAY_ONLY_HEADER_KEYS.includes(key);
    out[key] = createField(model[key], { displayOnly });
  });
  return out;
}

export function headerModelFromFields(
  header: Record<CashVoucherHeaderKey, IField<string>>,
): CashVoucherHeaderModel {
  const out = {} as CashVoucherHeaderModel;
  (Object.keys(header) as CashVoucherHeaderKey[]).forEach(key => {
    out[key] = header[key].value;
  });
  return out;
}

export function commitHeaderInitial(header: Record<CashVoucherHeaderKey, IField<string>>): Record<CashVoucherHeaderKey, IField<string>> {
  const next = { ...header };
  (Object.keys(next) as CashVoucherHeaderKey[]).forEach(key => {
    const f = next[key];
    const displayOnly = CASH_VOUCHER_DISPLAY_ONLY_HEADER_KEYS.includes(key);
    next[key] = {
      ...f,
      initialValue: f.value,
      isChanged: displayOnly ? false : false,
      error: undefined,
    };
  });
  return next;
}

export type CashVoucherLineFieldKey = keyof CashVoucherLineModel;

export interface CashVoucherLineFieldState {
  lineId: string;
  fields: Record<CashVoucherLineFieldKey, IField<string | number>>;
}

const LINE_DISPLAY_ONLY: CashVoucherLineFieldKey[] = ['accountName', 'customerName'];

export function initLineFields(model: CashVoucherLineModel, lineId: string): CashVoucherLineFieldState {
  const fields = {} as Record<CashVoucherLineFieldKey, IField<string | number>>;
  (Object.keys(model) as CashVoucherLineFieldKey[]).forEach(key => {
    const displayOnly = LINE_DISPLAY_ONLY.includes(key);
    fields[key] = createField(model[key], { displayOnly });
  });
  return { lineId, fields };
}

export function lineModelFromFields(line: CashVoucherLineFieldState): CashVoucherLineModel {
  const out = {} as CashVoucherLineModel;
  (Object.keys(line.fields) as CashVoucherLineFieldKey[]).forEach(key => {
    out[key] = line.fields[key].value as never;
  });
  return out;
}

export function linesModelsFromState(lines: CashVoucherLineFieldState[]): CashVoucherLineModel[] {
  return lines.map(lineModelFromFields);
}
